/**
 * @clawnify/db — dual-binding SQLite adapter for Clawnify apps.
 *
 * Auto-detects which storage backend is bound at runtime:
 *
 *   - **Production (Workers for Platforms)**: `env.DB` is a real
 *     `D1Database`. Calls go through D1's HTTP API.
 *
 *   - **Preview (Dynamic Workers + DO Facet)**: `env.STORAGE` is a
 *     capability-wrapped RPC binding handed in by the Clawnify
 *     supervisor. Calls go through the in-process Facet SQLite
 *     (µs latency, ~10x faster than D1).
 *
 * The same bundle works on both runtimes. User code uses
 * `query/get/run` — same signatures, same return shapes, regardless
 * of which binding is bound.
 *
 * Usage:
 *
 *   import { initDB, query, get, run } from "@clawnify/db";
 *
 *   app.use("*", async (c, next) => {
 *     initDB(c.env);  // detects env.DB or env.STORAGE
 *     await next();
 *   });
 *
 *   app.get("/tasks", async (c) => {
 *     const tasks = await query<Task>("SELECT * FROM tasks ORDER BY id");
 *     return c.json(tasks);
 *   });
 *
 * Init also accepts the raw `D1Database` directly for backwards
 * compatibility with apps already calling `initDB(c.env.DB)`.
 *
 * Also owns the `StorageBinding` RPC contract (used to live in the
 * separate `@clawnify/storage` package, now collapsed here — matches
 * `@vercel/postgres` shape where types + runtime ship together).
 * The Clawnify supervisor implements this interface and hands it to
 * dynamic isolates via `ctx.exports.Storage({ props })`.
 */

/**
 * Result of a SQL operation against an app's storage Facet.
 *
 * `rows` is the result set (empty for write-only statements).
 * `meta` carries D1/SQLite-style row counts so write statements can
 * report `changes` and `lastInsertRowid`. Optional because not every
 * implementation surfaces it.
 */
export interface StorageResult {
  rows: Record<string, unknown>[];
  meta?: StorageMeta;
}

export interface StorageMeta {
  changes?: number;
  last_row_id?: number;
}

/**
 * The minimal contract the supervisor's `Storage` `WorkerEntrypoint`
 * exposes to dynamic isolates. Mirrors D1's batch-style query API in
 * spirit but collapses prepare/bind/all into a single RPC call.
 */
export interface StorageBinding {
  query(sql: string, params?: unknown[]): Promise<StorageResult>;
}

export interface DBEnv {
  DB?: D1Database;
  STORAGE?: StorageBinding;
}

export interface RunResult {
  changes: number;
  lastInsertRowid: number;
}

interface DbImpl {
  query<T>(sql: string, params: unknown[]): Promise<T[]>;
  get<T>(sql: string, params: unknown[]): Promise<T | undefined>;
  run(sql: string, params: unknown[]): Promise<RunResult>;
}

let _impl: DbImpl | null = null;

/**
 * Initializes the adapter. Call once per request (or once per Worker
 * instance) before any query/get/run call.
 *
 * Accepts either:
 *   - The whole env object — preferred; the adapter picks `env.DB` or
 *     `env.STORAGE`.
 *   - A raw `D1Database` — legacy signature so today's `initDB(c.env.DB)`
 *     call sites keep working unchanged.
 */
export function initDB(arg: D1Database | DBEnv): void {
  if (arg && typeof (arg as D1Database).prepare === "function") {
    _impl = d1Impl(arg as D1Database);
    return;
  }
  const env = arg as DBEnv;
  if (env.DB && typeof env.DB.prepare === "function") {
    _impl = d1Impl(env.DB);
    return;
  }
  if (env.STORAGE && typeof env.STORAGE.query === "function") {
    _impl = storageImpl(env.STORAGE);
    return;
  }
  throw new Error(
    "@clawnify/db: initDB called without a usable binding (need env.DB or env.STORAGE)",
  );
}

function ensure(): DbImpl {
  if (!_impl) {
    throw new Error("@clawnify/db: not initialized — call initDB(env) first");
  }
  return _impl;
}

export async function query<T = Record<string, unknown>>(
  sql: string,
  params: unknown[] = [],
): Promise<T[]> {
  return ensure().query<T>(sql, params);
}

export async function get<T = Record<string, unknown>>(
  sql: string,
  params: unknown[] = [],
): Promise<T | undefined> {
  return ensure().get<T>(sql, params);
}

export async function run(
  sql: string,
  params: unknown[] = [],
): Promise<RunResult> {
  return ensure().run(sql, params);
}

function d1Impl(db: D1Database): DbImpl {
  return {
    async query<T>(sql: string, params: unknown[]) {
      const { results } = await db.prepare(sql).bind(...params).all<T>();
      return results ?? [];
    },
    async get<T>(sql: string, params: unknown[]) {
      const row = await db.prepare(sql).bind(...params).first<T>();
      return row ?? undefined;
    },
    async run(sql: string, params: unknown[]) {
      const r = await db.prepare(sql).bind(...params).run();
      return {
        changes: r.meta?.changes ?? 0,
        lastInsertRowid: Number(r.meta?.last_row_id ?? 0),
      };
    },
  };
}

function storageImpl(s: StorageBinding): DbImpl {
  return {
    async query<T>(sql: string, params: unknown[]) {
      const result = await s.query(sql, params);
      return (result.rows as T[]) ?? [];
    },
    async get<T>(sql: string, params: unknown[]) {
      const result = await s.query(sql, params);
      const rows = result.rows as T[];
      return rows[0] ?? undefined;
    },
    async run(sql: string, params: unknown[]) {
      const result = await s.query(sql, params);
      return {
        changes: result.meta?.changes ?? 0,
        lastInsertRowid: Number(result.meta?.last_row_id ?? 0),
      };
    },
  };
}
